import modal

app = modal.App("text-pipeline")

image = modal.Image.debian_slim()

@app.function(image=image)
def clean_text(text: str) -> str:
    return text.strip().lower()

@app.function(image=image)
def count_words(text: str) -> int:
    return len(text.split())

@app.function(image=image)
def summarize(original_text: str, word_count: int) -> dict:
    cleaned_length = len(original_text.strip().lower())
    return {
        "original_length": len(original_text),
        "word_count": word_count,
        "cleaned_length": cleaned_length,
    }

@app.local_entrypoint()
def main():
    sample_text = "  Hello World this is a TEST of the pipeline  "
    cleaned = clean_text.remote(sample_text)
    word_count = count_words.remote(cleaned)
    summary = summarize.remote(sample_text, word_count)

    d = modal.Dict.from_name("text-pipeline-output", create_if_missing=True)
    d["summary"] = summary
    d["pipeline_stages"] = 3

